using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class GroupPostConfiguration : IEntityTypeConfiguration<GroupPost>{public void Configure(EntityTypeBuilder<GroupPost> builder){builder.ToTable("group_posts");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("post_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.PostType).HasConversion<string>().HasMaxLength(30);builder.Property(e => e.Metadata).HasColumnType("jsonb");builder.Property(e => e.ModerationReason).HasMaxLength(50);builder.Property(e => e.ModerationSeverity).HasConversion<string>().HasMaxLength(10);builder.Property(e => e.ModerationAction).HasConversion<string>().HasMaxLength(20);builder.HasOne(e => e.Group).WithMany().HasForeignKey(e => e.GroupId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.AuthorUser).WithMany().HasForeignKey(e => e.AuthorUserId);builder.HasOne(e => e.ModeratedByUser).WithMany().HasForeignKey(e => e.ModeratedByUserId);builder.HasQueryFilter(e => e.DeletedAt == null);}}
